export function getArticleContent(id, article) {
  if (C[id]) return C[id];
  const tr = '<p>' + (article.tr?.d || '') + '. Bu konunun detayları için SilverAtlas araçlarını kullanabilirsiniz.</p>';
  return { tr, en: '<p>' + (article.en?.d || '') + '.</p>', ar: '<p>' + (article.ar?.d || '') + '.</p>' };
}
